// WRONG: load full entity, có tracking
var users = await db.Users.Where(u => u.IsActive).ToListAsync();

// BETTER: AsNoTracking
var users = await db.Users.Where(u => u.IsActive).AsNoTracking().ToListAsync();

// BEST: Projection (AsNoTracking tự động áp dụng)
var dtos = await db.Users
    .Where(u => u.IsActive)
    .Select(u => new UserListDto(u.Id, u.Name, u.Email, u.CreatedAt))
    .ToListAsync();

// Global config
db.ChangeTracker.QueryTrackingBehavior = QueryTrackingBehavior.NoTracking;

// AsNoTrackingWithIdentityResolution: dedup related entities
var orders = await db.Orders
    .Include(o => o.Customer) // cùng customer trong nhiều orders → chỉ 1 object
    .AsNoTrackingWithIdentityResolution()
    .ToListAsync();
